import React, { useState, useEffect, useCallback } from 'react';
import { User, MapPin, Package, LogOut, X, Moon, Sun, ArrowLeft, Plus, Edit2, Trash2 } from 'lucide-react';
import { toast } from 'react-toastify';
import AddressModal from './AddressModal';
import '../../assets/styles/UserSidebar.css';

const UserSidebar = ({ isOpen, onClose }) => {
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [activeView, setActiveView] = useState('menu'); // 'menu', 'profile', 'addresses'
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(false);
  const [profileForm, setProfileForm] = useState({ username: '', email: '', mobileNo: '' });

  // Modal State
  const [isAddressModalOpen, setIsAddressModalOpen] = useState(false);
  const [addressModalData, setAddressModalData] = useState(null);

  const fetchProfile = useCallback(async () => {
    const token = localStorage.getItem('token');
    if (!token) return;
    try {
      const res = await fetch('http://localhost:5000/api/auth/profile', {
        headers: { 'Authorization': `Bearer ${token}` }
      });
      const data = await res.json();
      if (data.success) {
        setUser(data.user);
        setProfileForm({
          username: data.user.username || '',
          email: data.user.email || '',
          mobileNo: data.user.mobileNo || ''
        });
      }
    } catch (err) {
      console.error('Failed to fetch profile', err);
    }
  }, []);

  useEffect(() => {
    if (isOpen) {
      fetchProfile();
      setActiveView('menu');
    }
  }, [isOpen, fetchProfile]);

  useEffect(() => {
    const isDark = document.body.classList.contains('dark-theme');
    setIsDarkMode(isDark);
  }, [isOpen]);

  const toggleTheme = () => {
    document.body.classList.toggle('dark-theme');
    const newMode = document.body.classList.contains('dark-theme');
    setIsDarkMode(newMode);
    toast.success(newMode ? 'Dark Theme enabled' : 'Light Theme enabled');
  };

  const handleLogout = () => {
    localStorage.removeItem('token');
    toast.info('You have securely logged out.');
    window.dispatchEvent(new Event('authChange'));
    onClose();
  };

  const handleProfileUpdate = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const res = await fetch('http://localhost:5000/api/auth/profile', {
        method: 'PUT',
        headers: { 
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${localStorage.getItem('token')}`
        },
        body: JSON.stringify(profileForm)
      });
      const data = await res.json();
      if (data.success) {
        toast.success(data.message);
        setUser(data.user);
      } else {
        toast.error(data.message);
      }
    } catch (err) {
      toast.error('Update failed');
    } finally {
      setLoading(false);
    }
  };

  const handleAddressAction = async (action, addressData) => {
    const addressId = addressData ? addressData.id : null;
    try {
      const payload = { action, addressId, addressData: action !== 'delete' ? addressData : null };
      const res = await fetch('http://localhost:5000/api/auth/address', {
        method: 'PUT',
        headers: { 
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${localStorage.getItem('token')}`
        },
        body: JSON.stringify(payload)
      });
      const data = await res.json();
      if (data.success) {
        toast.success(data.message);
        setUser(prev => ({ ...prev, addresses: data.addresses }));
        setIsAddressModalOpen(false); // Close Modal cleanly
      } else {
        toast.error(data.message);
      }
    } catch (err) {
      toast.error('Address update failed');
    }
  };

  const openAddressModal = (address = null) => {
    setAddressModalData(address);
    setIsAddressModalOpen(true);
  };

  const renderMenu = () => (
    <>
      <div className="sidebar-menu">
        <button className="menu-item" onClick={() => setActiveView('profile')}>
          <User size={20} />
          <span>Profile Details</span>
        </button>
        <button className="menu-item" onClick={() => setActiveView('addresses')}>
          <MapPin size={20} />
          <span>Saved Addresses</span>
        </button>
        <button className="menu-item" onClick={() => toast.info('Order History coming soon.')}>
          <Package size={20} />
          <span>Order History</span>
        </button>
      </div>

      <div className="sidebar-footer">
        <button className="theme-toggle-btn" onClick={toggleTheme}>
          {isDarkMode ? <><Sun size={20} /><span>Switch to Light Mode</span></> : <><Moon size={20} /><span>Switch to Dark Mode</span></>}
        </button>
        <button className="logout-btn" onClick={handleLogout}>
          <LogOut size={20} />
          <span>Log Out</span>
        </button>
      </div>
    </>
  );

  const renderProfile = () => (
    <div className="sidebar-subview">
      <button className="back-btn" onClick={() => setActiveView('menu')}><ArrowLeft size={20} /> Back</button>
      <div className="subview-content">
        <h4>User Profile</h4>
        <form onSubmit={handleProfileUpdate} className="sidebar-form">
          <label>Full Name</label>
          <input type="text" value={profileForm.username} onChange={e => setProfileForm({...profileForm, username: e.target.value})} required />
          <label>Email Address</label>
          <input type="email" value={profileForm.email} onChange={e => setProfileForm({...profileForm, email: e.target.value})} required />
          <label>Mobile Number</label>
          <input type="tel" value={profileForm.mobileNo} onChange={e => setProfileForm({...profileForm, mobileNo: e.target.value})} required />
          <button type="submit" disabled={loading} className="save-btn">{loading ? 'Saving...' : 'Update Details'}</button>
        </form>

        <div className="profile-summary-addresses" style={{ marginTop: '30px' }}>
          <h4>Primary Address Summary</h4>
          {user?.addresses?.length > 0 ? (
            <div className="address-card" style={{ padding: '12px' }}>
              <p><strong>{user.addresses[0].type}:</strong> {user.addresses[0].street ? `${user.addresses[0].street}, ${user.addresses[0].city}` : user.addresses[0].fullAddress || 'Unknown'}</p>
            </div>
          ) : (
            <p style={{ fontSize: '0.85rem', opacity: 0.7, color: 'var(--text-main)' }}>No addresses linked to this account.</p>
          )}
        </div>
      </div>
    </div>
  );

  const renderAddresses = () => (
    <div className="sidebar-subview">
      <button className="back-btn" onClick={() => setActiveView('menu')}><ArrowLeft size={20} /> Back</button>
      <div className="subview-content">
        <h4>Saved Addresses</h4>
        <div className="address-list">
          {user?.addresses?.length > 0 ? user.addresses.map(addr => (
            <div key={addr.id} className="address-card">
              <div className="address-card-header">
                <strong>{addr.type || 'Home'}</strong>
                <div className="address-actions">
                  <button onClick={() => openAddressModal(addr)} className="icon-btn edit" aria-label="Edit"><Edit2 size={16}/></button>
                  <button onClick={() => handleAddressAction('delete', {id: addr.id})} className="icon-btn delete" aria-label="Delete"><Trash2 size={16}/></button>
                </div>
              </div>
              <p>{addr.street && `${addr.street}, `}{addr.city && `${addr.city}, `}{addr.state}</p>
              <p>{addr.pincode}</p>
              {/* Backwards compatibility for old records */}
              {!addr.street && addr.fullAddress && <p>{addr.fullAddress}</p>}
            </div>
          )) : <p className="empty-text" style={{ fontSize: '0.9rem', opacity: 0.8, color: 'var(--text-main)' }}>No saved addresses found.</p>}
        </div>
        <button className="add-action-btn" onClick={() => openAddressModal(null)}>
          <Plus size={20} /> Add New Address
        </button>
      </div>
    </div>
  );

  return (
    <>
      <div className={`sidebar-overlay ${isOpen ? 'active' : ''}`} onClick={onClose} />
      <div className={`user-sidebar ${isOpen ? 'active' : ''}`}>
        <div className="sidebar-header">
          <button className="close-btn" onClick={onClose} aria-label="Close"><X size={24} /></button>
          <div className="user-info">
            <div className="user-avatar"><User size={32} color="#fff" /></div>
            <h3>{user ? user.username : 'Welcome back!'}</h3>
            <p>{user ? user.email : 'Heritage Premium Member'}</p>
          </div>
        </div>

        {activeView === 'menu' && renderMenu()}
        {activeView === 'profile' && renderProfile()}
        {activeView === 'addresses' && renderAddresses()}
      </div>

      <AddressModal 
        isOpen={isAddressModalOpen} 
        onClose={() => setIsAddressModalOpen(false)} 
        initialData={addressModalData}
        onSave={handleAddressAction}
      />
    </>
  );
};

export default React.memo(UserSidebar);
